import{c as a,Q as e,j as r,m as s}from"./chunks/framework.D9IbVcwA.js";const b=JSON.parse('{"title":"029-gui-canvas-2 · GUI Canvas","description":"","frontmatter":{"title":"029-gui-canvas-2 · GUI Canvas"},"headers":[],"relativePath":"hands-on/029-gui-canvas-2.md","filePath":"hands-on/029-gui-canvas-2.md","lastUpdated":1779686691000}'),n={name:"hands-on/029-gui-canvas-2.md"};function d(o,t,i,p,l,c){return e(),r("div",null,[...t[0]||(t[0]=[s(`<h1 id="基础图元绘制-矩形填充、描边、bresenham-直线与位图" tabindex="-1">基础图元绘制：矩形填充、描边、Bresenham 直线与位图 <a class="header-anchor" href="#基础图元绘制-矩形填充、描边、bresenham-直线与位图" aria-label="Permalink to &quot;基础图元绘制：矩形填充、描边、Bresenham 直线与位图&quot;">​</a></h1><blockquote><p>标签：Bresenham, draw_rect, draw_line, draw_bitmap, blit, 2D primitives 前置：<a href="./029-gui-canvas-1">029 Canvas 架构</a></p></blockquote><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>上一章我们搭好了 Canvas 的双缓冲架构——初始化、draw_pixel 和 flip。但一个只能画单个像素的画布显然不够用，本章我们要给它加上真正的图元绘制能力：矩形填充、矩形描边、Bresenham 直线算法、像素位图渲染，以及画布间的 blit 操作。这些都是 2D 图形系统的基本功——从 Linux 的 libdrm 到 SerenityOS 的 LibGfx Painter 类，每个图形库都要实现这些基本原语。</p><p>完成本章后，我们的 Canvas 将具备完整的 2D 绘制能力，可以在屏幕上画出任意形状的图形组合。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="矩形绘制-填充-vs-描边" tabindex="-1">矩形绘制：填充 vs 描边 <a class="header-anchor" href="#矩形绘制-填充-vs-描边" aria-label="Permalink to &quot;矩形绘制：填充 vs 描边&quot;">​</a></h3><p>矩形是最基本的 2D 图元，也是最常用的。Canvas 提供两种矩形操作：<code>draw_rect</code>（实心填充）和 <code>draw_rect_outline</code>（1 像素宽的边框描边）。</p><p>填充矩形的实现很直观——双重循环遍历行和列，对每个像素调用像素索引计算。但有一个优化点：我们不需要通过 draw_pixel 来写（它会做边界检查），而是直接在循环中计算索引并写入 back buffer。这比逐像素调用快得多，因为省去了重复的函数调用开销和边界判断。</p><p>描边矩形稍微复杂一些——它不是简单地画四条线，而是分别画上边、下边、左边、右边四条 1 像素宽的线段。需要特别注意角落像素的处理（不能重复写入），以及宽度和高度为 0 的退化情况。我们的实现中，上下两条边通过水平循环 draw_pixel 画，左右两条边通过垂直循环 draw_pixel 画。</p><h3 id="bresenham-直线算法" tabindex="-1">Bresenham 直线算法 <a class="header-anchor" href="#bresenham-直线算法" aria-label="Permalink to &quot;Bresenham 直线算法&quot;">​</a></h3><p>直线绘制是计算机图形学中最经典的算法之一。Bresenham 算法的核心思想是：只用整数加法和比较来决定下一个像素的位置，完全避免浮点运算和乘法。这在一个没有 FPU 支持的内核环境里尤为重要——虽然 x86_64 有 SSE/XMM 寄存器，但内核代码通常不使用浮点指令。</p><p>算法的输入是两个端点 (x0, y0) 和 (x1, y1)，输出是一系列像素坐标。核心逻辑是维护一个误差值 err，每次迭代根据 err 的符号决定在主方向和副方向上各走一步还是只在主方向上走一步。需要注意的是，直线可能走向任意方向（8 个象限），所以 dx 和 dy 都要取绝对值，步进方向用 step_x 和 step_y 的正负号来表示。</p><p>与 SerenityOS 的 Painter 类对比：SerenityOS 的 draw_line 支持抗锯齿（anti-aliasing），使用的是 Wu 算法或类似方法。Cinux 目前只实现了基本的 Bresenham，输出的是锯齿状的像素阶梯——对于一个教学内核来说完全够用，后续如果想改善视觉效果可以加抗锯齿。</p><h3 id="位图渲染与色彩键透明" tabindex="-1">位图渲染与色彩键透明 <a class="header-anchor" href="#位图渲染与色彩键透明" aria-label="Permalink to &quot;位图渲染与色彩键透明&quot;">​</a></h3><p><code>draw_bitmap</code> 方法用于渲染一个像素数组到 Canvas 上。这个方法接收一个 <code>uint32_t*</code> 像素数组（row-major 排列），把每个非零像素写入 back buffer。零值像素（0x00000000）被视为完全透明，跳过不写。这是一种最简单的「色彩键」（color key）透明机制——选一个特定颜色值作为透明色。</p><p>这种透明方案虽然粗糙（无法实现半透明效果），但在内核级别的图形系统中非常实用。它不需要混合运算，性能开销极低，而且对后续的图标渲染、光标绘制等场景完全够用。</p><h3 id="blit-操作-画布间像素拷贝" tabindex="-1">Blit 操作：画布间像素拷贝 <a class="header-anchor" href="#blit-操作-画布间像素拷贝" aria-label="Permalink to &quot;Blit 操作：画布间像素拷贝&quot;">​</a></h3><p><code>blit</code> 方法实现从一个 Canvas 拷贝矩形区域到另一个 Canvas。这是窗口系统的核心操作——每个窗口在自己的离屏 Canvas 上绘制内容，然后窗口管理器通过 blit 把窗口内容合成到屏幕 Canvas 上。</p><p>blit 的一个关键设计是目标坐标使用有符号整数（int32_t）。为什么？因为窗口可能被拖动到屏幕边缘之外——比如窗口顶部被拖出屏幕顶部，此时目标 y 坐标是负数。blit 需要正确处理这种「部分可见」的情况：跳过目标 y 坐标为负的行，调整源区域的起始位置来补偿偏移量。</p><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-实现矩形填充-draw-rect" tabindex="-1">Step 1: 实现矩形填充 draw_rect <a class="header-anchor" href="#step-1-实现矩形填充-draw-rect" aria-label="Permalink to &quot;Step 1: 实现矩形填充 draw_rect&quot;">​</a></h3><p><strong>目标</strong>: 实现实心矩形填充，直接在 back buffer 上批量写入像素。</p><p><strong>设计思路</strong>: 双重循环遍历行和列。外层循环从 y 到 y+h，内层循环从 x 到 x+w。循环条件同时检查边界（row &lt; height_, col &lt; width_），避免越界写入。每行的起始索引通过 <code>row * pixels_per_row</code> 计算，然后加上列偏移。</p><p><strong>实现约束</strong>: 直接操作 back_buf_ 数组，不调用 draw_pixel。使用 <code>pitch_ / 4</code> 作为行步进（pixels_per_row），不是 width_。</p><p><strong>踩坑预警</strong>: 如果你的矩形坐标 (x, y) 加上宽高 (w, h) 超过了 Canvas 的范围，循环的边界检查必须正确——<code>row &lt; y + h &amp;&amp; row &lt; height_</code>，不能只检查 <code>row &lt; height_</code>，否则当 y + h &gt; height_ 时会溢出。同理 col 的检查。</p><p><strong>验证</strong>: 画一个红色矩形在 (10, 10) 位置，大小 50x30，flip 后检查 framebuffer 上 (10, 10) 和 (35, 25) 的像素值是否为 0x00FF0000。</p><h3 id="step-2-实现矩形描边-draw-rect-outline" tabindex="-1">Step 2: 实现矩形描边 draw_rect_outline <a class="header-anchor" href="#step-2-实现矩形描边-draw-rect-outline" aria-label="Permalink to &quot;Step 2: 实现矩形描边 draw_rect_outline&quot;">​</a></h3><p><strong>目标</strong>: 实现 1 像素宽的矩形边框。</p><p><strong>设计思路</strong>: 分别画四条边——上边、下边、左边、右边。上下边是水平方向的像素行，用循环从 x 到 x+w 调用 draw_pixel。左右边是垂直方向的像素列，从 y 到 y+h 调用 draw_pixel。</p><p><strong>实现约束</strong>: 底边 y 坐标是 y + h - 1（不是 y + h），右边 x 坐标是 x + w - 1（不是 x + w）。需要检查 h &gt; 0 和 w &gt; 0 来避免下溢（y + h - 1 在 h=0 时会下溢为 uint32_t 最大值）。</p><p><strong>验证</strong>: 画一个蓝色描边矩形在 (50, 50) 位置，大小 20x10，flip 后检查四角和内部像素。四角应该是蓝色，内部 (51, 51) 应该保持背景色。</p><h3 id="step-3-实现-bresenham-直线-draw-line" tabindex="-1">Step 3: 实现 Bresenham 直线 draw_line <a class="header-anchor" href="#step-3-实现-bresenham-直线-draw-line" aria-label="Permalink to &quot;Step 3: 实现 Bresenham 直线 draw_line&quot;">​</a></h3><p><strong>目标</strong>: 实现任意方向的直线绘制。</p><p><strong>设计思路</strong>: 经典的 Bresenham 算法。首先计算 dx 和 dy 的绝对值以及步进方向。然后初始化 err = dx - dy，进入循环。每次迭代画当前像素，然后计算 2*err，根据其与 -dy 和 dx 的关系决定 x 和/或 y 方向的步进。当到达终点 (x1, y1) 时退出循环。</p><p><strong>实现约束</strong>: 所有计算使用 int32_t（有符号整数），因为 dx 和 dy 可能为负。但最终的像素坐标是 uint32_t，所以步进时需要 <code>static_cast&lt;uint32_t&gt;(static_cast&lt;int32_t&gt;(cx) + step_x)</code> 这种看起来奇怪但正确的写法——先转成有符号做加减，再转回无符号。</p><p><strong>踩坑预警</strong>: 最容易出错的地方是循环终止条件。必须是 <code>cx == x1 &amp;&amp; cy == y1</code>，不能只检查 cx == x1（水平线时 cy 永远不变，但如果是近水平线 cy 可能还没到终点就因为 cx 先到了而退出）。</p><p><strong>验证</strong>: 画一条从 (0, 0) 到 (30, 30) 的黄色对角线，flip 后检查起点 (0, 0) 和终点 (30, 30) 的像素值。</p><h3 id="step-4-实现位图渲染-draw-bitmap" tabindex="-1">Step 4: 实现位图渲染 draw_bitmap <a class="header-anchor" href="#step-4-实现位图渲染-draw-bitmap" aria-label="Permalink to &quot;Step 4: 实现位图渲染 draw_bitmap&quot;">​</a></h3><p><strong>目标</strong>: 把像素数组渲染到 Canvas 上，零值像素视为透明。</p><p><strong>设计思路</strong>: 双重循环遍历位图的行和列。对于每个像素，从源数组读取颜色值，如果是 0x00000000 则跳过，否则写入 back buffer 的对应位置。行和列都有边界裁剪——超过 Canvas 范围的像素直接不画。</p><p><strong>实现约束</strong>: 源数组的索引是 <code>row * w + col</code>（w 是位图宽度，不是 pitch）。目标 Canvas 的索引是 <code>(y + row) * pixels_per_row + (x + col)</code>（使用 pitch 计算）。</p><p><strong>验证</strong>: 构造一个小的 4x4 像素数组（中间两个像素有颜色，周围是 0），渲染到 Canvas 上，检查只有中间两个像素被写入。</p><h3 id="step-5-实现-blit-画布间拷贝" tabindex="-1">Step 5: 实现 blit 画布间拷贝 <a class="header-anchor" href="#step-5-实现-blit-画布间拷贝" aria-label="Permalink to &quot;Step 5: 实现 blit 画布间拷贝&quot;">​</a></h3><p><strong>目标</strong>: 从源 Canvas 拷贝矩形区域到当前 Canvas。</p><p><strong>设计思路</strong>: 遍历 h 行。对于每一行：检查目标行号（dst_y + row）是否在合法范围内——负数行跳过，超过高度则 break。然后处理列方向：如果 dst_x 为负数，需要从源区域跳过相应列数（col_skip = -dst_x），调整有效起始位置。逐像素拷贝，边界检查两端。</p><p><strong>实现约束</strong>: dst_x 和 dst_y 是 int32_t（有符号），用于支持窗口部分在屏幕外的情况。源区域用 uint32_t 索引。两个 Canvas 可能有不同的 pitch。</p><p><strong>踩坑预警</strong>: 当 dst_x 为负数时，不能简单地从源的第 |dst_x| 列开始拷贝——你需要同时调整源起始列 sx 和拷贝列数。col_count = w - col_skip，如果 col_count &lt;= 0 说明整个 blit 区域都在屏幕外，直接跳过。</p><p><strong>验证</strong>: 创建一个小的离屏 Canvas，画一个绿色矩形，然后 blit 到屏幕 Canvas 上。检查屏幕上对应区域的像素值。</p><h3 id="step-6-实现-gui-demo-综合测试" tabindex="-1">Step 6: 实现 GUI Demo 综合测试 <a class="header-anchor" href="#step-6-实现-gui-demo-综合测试" aria-label="Permalink to &quot;Step 6: 实现 GUI Demo 综合测试&quot;">​</a></h3><p><strong>目标</strong>: 编写一个综合测试，在屏幕上画 10 个随机颜色的矩形和 &quot;Cinux GUI&quot; 标题文字，作为视觉里程碑验证。</p><p><strong>设计思路</strong>: 这个测试用 LCG（线性同余伪随机数生成器）生成确定性随机数——每次运行结果完全相同，方便调试。先生成深色背景 (0x001A1A2E)，然后循环 10 次生成随机位置、大小和颜色的矩形。最后在顶部居中位置画白色文字。每个矩形的颜色使用 0x40-0xFF 范围的 RGB 分量，保证颜色足够亮、不会和深色背景混在一起。</p><p><strong>实现约束</strong>: LCG 的初始种子为 12345，乘数 1103515245，增量 12345。<code>next_color()</code> 生成可见颜色——每个通道至少 0x40（64/255），最大 0xFF（255/255）。文字居中的计算是 <code>(canvas_width - text_pixel_width) / 2</code>，其中 <code>text_pixel_width = num_chars * font_width</code>。</p><p><strong>踩坑预警</strong>: 随机矩形的位置需要保证不超出 Canvas 范围——<code>rng.next() % (canvas.width() - 100)</code> 确保矩形至少距离右边 100 像素。如果不用这个偏移，矩形可能部分超出 Canvas，虽然 draw_rect 有边界检查不会崩溃，但视觉上矩形会被裁剪，影响验证效果。</p><p><strong>验证</strong>: 运行后 QEMU 窗口显示深色背景 + 10 个彩色矩形 + 白色 &quot;Cinux GUI&quot; 文字。串口输出 <code>[BIG] GUI demo rendered to framebuffer.</code>。</p><h3 id="step-7-设计-canvas-的-cmake-编译条件" tabindex="-1">Step 7: 设计 Canvas 的 CMake 编译条件 <a class="header-anchor" href="#step-7-设计-canvas-的-cmake-编译条件" aria-label="Permalink to &quot;Step 7: 设计 Canvas 的 CMake 编译条件&quot;">​</a></h3><p><strong>目标</strong>: 配置 CMakeLists.txt，使 Canvas 和 GUI 相关代码只在启用 CINUX_GUI 时编译。</p><p><strong>设计思路</strong>: 在顶层 CMakeLists.txt 中添加 <code>option(CINUX_GUI &quot;Enable GUI subsystem&quot; OFF)</code>。当启用时，添加编译定义 <code>-DCINUX_GUI</code>，并包含 <code>kernel/gui/CMakeLists.txt</code>（GUI 子系统的源文件列表）。Canvas.cpp 和 GUI init 代码通过 <code>#ifdef CINUX_GUI</code> 条件编译，在非 GUI 模式下不会编译也不会链接。</p><p><strong>实现约束</strong>: kernel/drivers/canvas.cpp 应该只在 CINUX_GUI 启用时加入编译列表。kernel/test/test_canvas.cpp 中的 GUI 测试也用 <code>#ifdef CINUX_GUI</code> 包裹。PIT 的 tick callback 部分同样用这个宏控制。</p><p><strong>验证</strong>: 分别用 <code>-DCINUX_GUI=ON</code> 和 <code>-DCINUX_GUI=OFF</code> 编译，确认两种模式都能正常编译通过。OFF 模式下运行不应该出现任何 GUI 相关的串口输出。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mkdir -p build &amp;&amp; cd build</span></span>
<span class="line"><span>cmake .. -DCINUX_GUI=ON &amp;&amp; make -j$(nproc)</span></span>
<span class="line"><span>./run.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>如果你实现了 GUI demo 测试（画随机矩形 + 标题文字），运行后应该能在 QEMU 窗口看到彩色的矩形散布在深色背景上。</p><p>禁用 GUI 模式编译验证兼容性：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cmake .. -DCINUX_GUI=OFF &amp;&amp; make -j$(nproc)</span></span>
<span class="line"><span>./run.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>此时应看到 Console 正常工作，Canvas GUI Tests 被跳过。</p><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p><strong>直线画歪或缺失像素</strong>：检查 Bresenham 的 err 更新逻辑——应该是 <code>err -= dy</code> 和 <code>err += dx</code>，不是 <code>err -= dx</code> 和 <code>err += dy</code>。另外确认 step_x 和 step_y 的正负号与 dx/dy 的方向一致。</p><p><strong>blit 后画面位置不对</strong>：打印 dst_x、dst_y、col_skip 的值到串口，确认坐标计算是否正确。特别是 dst_x 为负数时的逻辑——这是最容易出 bug 的地方。</p><p><strong>draw_bitmap 透明度不生效</strong>：检查你的色彩键判断是否是 <code>color == 0x00000000</code>，不是 <code>color == 0</code>（虽然这两个值相同，但意图不同，用前者更清晰）。确认源像素数组的排列是 row-major 的。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方法</th><th>功能</th><th>关键算法</th></tr></thead><tbody><tr><td>draw_rect</td><td>实心矩形填充</td><td>双重循环 + 直接写入 back buffer</td></tr><tr><td>draw_rect_outline</td><td>矩形描边</td><td>四条 1px 线段组合</td></tr><tr><td>draw_line</td><td>直线绘制</td><td>Bresenham 整数算法，全象限支持</td></tr><tr><td>draw_bitmap</td><td>像素数组渲染</td><td>逐像素拷贝 + 色彩键透明</td></tr><tr><td>blit</td><td>画布间拷贝</td><td>有符号目标坐标 + 裁剪</td></tr></tbody></table><p>到这里 Canvas 的图元绘制能力已经完整了。下一章我们来处理最后一个关键模块：PSF2 位图字体的文字渲染，以及把所有这些组合起来——PIT 定时器回调驱动的自动刷新，和为 GUI 做准备的堆内存安全修复。</p><h2 id="设计决策总结" tabindex="-1">设计决策总结 <a class="header-anchor" href="#设计决策总结" aria-label="Permalink to &quot;设计决策总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>决策点</th><th>我们的选择</th><th>备选方案</th><th>理由</th></tr></thead><tbody><tr><td>直线算法</td><td>Bresenham (整数)</td><td>DDA (浮点)</td><td>内核无 FPU，纯整数更快</td></tr><tr><td>描边矩形</td><td>四条线段独立画</td><td>单次循环画全部边</td><td>实现简单，无性能问题</td></tr><tr><td>位图透明</td><td>色彩键 (0=透明)</td><td>Alpha 通道</td><td>无混合运算，性能零开销</td></tr><tr><td>blit 目标坐标</td><td>int32_t (有符号)</td><td>uint32_t (无符号)</td><td>支持窗口部分在屏幕外</td></tr><tr><td>描边角落</td><td>允许重复像素</td><td>精确合并</td><td>重复写入同一颜色无副作用</td></tr></tbody></table><h2 id="性能考虑" tabindex="-1">性能考虑 <a class="header-anchor" href="#性能考虑" aria-label="Permalink to &quot;性能考虑&quot;">​</a></h2><p>图元绘制的性能在 GUI 系统中非常重要——尤其是合成阶段，窗口管理器需要每帧把所有窗口 blit 到屏幕上。对于 1024x768 的 Canvas，以下是一些关键的性能数据点：</p><p>一个 100x50 的矩形填充需要 5000 次数组写入，在 1GHz CPU 上大约需要 5-10 微秒。一条 1000 像素的对角线大约需要 1000 次 draw_pixel 调用（每次有边界检查和索引计算），约 2-5 微秒。一帧完整的 flip（3MB 拷贝）大约需要 1-2 毫秒。所以以 100 Hz PIT 频率刷新（10ms 间隔），flip 占用约 10-20% 的帧时间，留给绘制操作还有 8-9ms，足够绘制几十个窗口和大量图元。</p>`,78)])])}const _=a(n,[["render",d]]);export{b as __pageData,_ as default};
